python3 << 'EOF'
import csv
import os

# Sample configs for each OpName
op_examples = {}

for root, dirs, files in os.walk('/home/nick/work/ai_iree/dataset_modelzoo'):
    if 'raw.csv' in files:
        with open(os.path.join(root, 'raw.csv'), 'r') as f:
            reader = csv.reader(f)
            next(reader)  # skip header
            for row in reader:
                if len(row) < 5:
                    continue
                op_name = row[1]
                if op_name not in op_examples:
                    op_examples[op_name] = []
                if len(op_examples[op_name]) < 5:
                    op_examples[op_name].append({
                        'shape': row[2],
                        'config': row[4],
                        'cycles': row[5],
                        'status': row[6]
                    })

for op in sorted(op_examples.keys()):
    print(f"\n{op}:")
    for i, ex in enumerate(op_examples[op][:3]):
        print(f"  Example {i+1}:")
        print(f"    Shape: {ex['shape']}")
        print(f"    Config: {ex['config']}")
        print(f"    Status: {ex['status']}")
EOF

